// Helper to extract a clean URL component
export const getArticleUrl = (repo: string, slug: string) => {
  const shortRepo = repo.split('/')[1] || repo;
  const encodedSlug = encodeURIComponent(slug);
  return `/article/${shortRepo}/${encodedSlug}`;
};
